import sys
from sys import stdin

def solve():
    data = stdin.buffer.read().split()
    idx = 0
    n = int(data[idx]); idx+=1
    m = int(data[idx]); idx+=1

    grid = []
    for i in range(n):
        grid.append(data[idx].decode()); idx+=1

    INF = m + 1
    # noexit_thresh[r][c] for empty cells: min x1 (0-indexed) s.t. exit_sub(r,c,x1)=True
    nt = [[INF]*m for _ in range(n)]

    for r in range(n):
        for c in range(m):
            if grid[r][c] == 'X':
                nt[r][c] = INF
                continue
            if r == 0:
                nt[r][c] = 0
            elif c == 0:
                nt[r][c] = 0
            else:
                # exit_sub(r,c,x1)=True iff x1==c or exit_sub(r-1,c,x1) or exit_sub(r,c-1,x1)
                # noexit_thresh = min(c, nt[r-1][c], nt[r][c-1])
                val = c  # x1==c always makes it true
                if grid[r-1][c] == '.':
                    val = min(val, nt[r-1][c])
                if grid[r][c-1] == '.':
                    val = min(val, nt[r][c-1])
                nt[r][c] = val

    # For each filled cell (r,c) with r>0, c>0: threshold_bad = min(c, T1, T2)
    # g[c] = max threshold_bad over all filled cells in column c with r>0
    g = [0] * (m + 1)  # 0-indexed columns

    for r in range(1, n):
        for c in range(1, m):
            if grid[r][c] == 'X':
                T1 = nt[r-1][c] if grid[r-1][c] == '.' else INF
                T2 = nt[r][c-1] if grid[r][c-1] == '.' else INF
                tb = min(c, T1, T2)
                if tb > g[c]:
                    g[c] = tb

    # prefix max of g: G[c] = max(g[0..c])
    G = [0] * (m + 1)
    G[0] = g[0]
    for c in range(1, m):
        G[c] = max(G[c-1], g[c])

    q = int(data[idx]); idx+=1
    out = []
    for _ in range(q):
        x1 = int(data[idx])-1; idx+=1
        x2 = int(data[idx])-1; idx+=1
        # NO iff exists filled (r,c) with r>0, c<=x2, threshold_bad(r,c) > x1
        # i.e., G[x2] > x1
        if G[x2] > x1:
            out.append("NO")
        else:
            out.append("YES")

    print('\n'.join(out))

solve()

